const data = $input.first().json;
const projects = data.list || [];

if (projects.length === 0) {
  return [{ json: { error: 'No active projects found', skip: true } }];
}

return projects.map(p => ({
  json: {
    project_id: p.project_id,
    topvisor_project_id: p.topvisor_project_id || 24810550,
    city: p.city || 'Москва',
    domain: p.domain,
    is_cron_trigger: true,
    workflow_version: 'v3.0'
  }
}));

const body = $input.first().json.body || $input.first().json;
const { project_id, topvisor_project_id, city, is_cron_trigger } = body;

// ── Auth check (webhook only) ──
const headers = $input.first().json.headers || {};
if (!is_cron_trigger) {
  const authHeader = headers.authorization || headers.Authorization || '';
  const expectedToken = $env.WEBHOOK_SECRET || '';
  if (expectedToken && authHeader !== `Bearer ${expectedToken}`) {
    throw new Error('Unauthorized: invalid or missing Bearer token');
  }
}

if (!project_id) throw new Error('project_id обязателен');

// ── Расширенная карта регионов (15 городов) ──
const regionMap = {
  'Москва':            { yandex: 213,  google: 2840 },
  'Санкт-Петербург':   { yandex: 2,    google: 2841 },
  'Новосибирск':       { yandex: 65,   google: 2842 },
  'Екатеринбург':      { yandex: 54,   google: 2843 },
  'Казань':            { yandex: 43,   google: 2844 },
  'Нижний Новгород':   { yandex: 47,   google: 2845 },
  'Краснодар':         { yandex: 35,   google: 2846 },
  'Челябинск':         { yandex: 56,   google: 2847 },
  'Самара':            { yandex: 51,   google: 2848 },
  'Ростов-на-Дону':    { yandex: 39,   google: 2849 },
  'Воронеж':           { yandex: 36,   google: 2850 },
  'Уфа':               { yandex: 172,  google: 2851 },
  'Красноярск':        { yandex: 62,   google: 2852 },
  'Пермь':             { yandex: 50,   google: 2853 },
  'Волгоград':         { yandex: 38,   google: 2854 }
};

const selectedCity = city || 'Москва';
const regions = regionMap[selectedCity];

if (!regions) {
  throw new Error(`Город "${selectedCity}" не найден в карте регионов. Доступные: ${Object.keys(regionMap).join(', ')}`);
}

return [{ json: {
  project_id,
  topvisor_project_id: topvisor_project_id || 24810550,
  city: selectedCity,
  yandex_region: regions.yandex,
  google_region: regions.google,
  is_cron_trigger: !!is_cron_trigger,
  workflow_version: 'v3.0',
  started_at: new Date().toISOString()
}}];

const nocodb = $('NocoDB Get Clusters').first().json;
const validate = $('Validate Input + Auth').first().json;

// ── Existing keywords from Topvisor (для дедупликации) ──
let existingKeywords = new Set();
try {
  const existing = $('Topvisor Get Existing Keywords').first().json;
  const kws = existing.result || existing.list || [];
  for (const k of kws) {
    existingKeywords.add((k.name || '').trim().toLowerCase());
  }
} catch(e) { /* first run — no existing keywords */ }

// ── RAG контекст от конкурентов ──
let ragContext = '';
try {
  const rag = $('RAG Qdrant Search Competitors').first().json;
  const results = rag.result || [];
  ragContext = results.map(r => r.payload?.content || '').filter(Boolean).join('\n');
} catch(e) { /* no RAG data yet */ }

// ── Парсинг кластеров ──
const clusters = nocodb.list || [];
if (clusters.length === 0) {
  throw new Error('Кластеры не найдены для project_id: ' + validate.project_id);
}

const keywords = [];
const newKeywords = [];
const duplicates = [];
const seen = new Set();

for (const cluster of clusters) {
  let kws = [];
  try {
    const parsed = JSON.parse(cluster.keywords || '[]');
    kws = Array.isArray(parsed) ? parsed : [parsed];
  } catch(e) {
    kws = [{ keyword: cluster.main_keyword }];
  }

  for (const kw of kws) {
    const name = (typeof kw === 'string' ? kw : kw.keyword || '').trim().toLowerCase();
    if (!name || seen.has(name)) continue;
    seen.add(name);

    const entry = {
      name,
      url: cluster.recommended_url || '/',
      cluster_name: cluster.cluster_name,
      page_type: cluster.page_type || 'commercial',
      search_volume: kw.volume || cluster.total_volume || 0,
      intent: cluster.intent || 'commercial'
    };

    keywords.push(entry);

    if (existingKeywords.has(name)) {
      duplicates.push(name);
    } else {
      newKeywords.push(entry);
    }
  }

  // main_keyword отдельно
  const main = (cluster.main_keyword || '').trim().toLowerCase();
  if (main && !seen.has(main)) {
    seen.add(main);
    const entry = {
      name: main,
      url: cluster.recommended_url || '/',
      cluster_name: cluster.cluster_name,
      page_type: cluster.page_type || 'commercial',
      search_volume: cluster.total_volume || 0,
      intent: cluster.intent || 'commercial'
    };
    keywords.push(entry);
    if (existingKeywords.has(main)) {
      duplicates.push(main);
    } else {
      newKeywords.push(entry);
    }
  }
}

// ── Батчинг по 100 ключей ──
const BATCH_SIZE = 100;
const batches = [];
for (let i = 0; i < newKeywords.length; i += BATCH_SIZE) {
  batches.push(newKeywords.slice(i, i + BATCH_SIZE));
}

return [{ json: {
  project_id: validate.project_id,
  topvisor_project_id: validate.topvisor_project_id,
  city: validate.city,
  yandex_region: validate.yandex_region,
  google_region: validate.google_region,
  all_keywords: keywords,
  new_keywords: newKeywords,
  duplicates_skipped: duplicates.length,
  keywords_total: keywords.length,
  keywords_new: newKeywords.length,
  clusters_count: clusters.length,
  batches,
  batches_count: batches.length,
  rag_context: ragContext,
  existing_in_topvisor: existingKeywords.size
}}];

const data = $input.first().json;

if (data.keywords_new === 0) {
  return [{ json: { ...data, add_result: 'skipped_no_new_keywords', added_count: 0 } }];
}

// Отправляем батчами
const results = [];

for (let i = 0; i < data.batches.length; i++) {
  const batch = data.batches[i];
  const names = batch.map(k => k.name);

  try {
    const resp = await fetch('https://api.topvisor.com/v2/json/set/keywords_2/add', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'User-Id': $env.TOPVISOR_USER_ID,
        'Authorization': `Bearer ${$env.TOPVISOR_TOKEN}`
      },
      body: JSON.stringify({
        project_id: data.topvisor_project_id,
        keywords: names,
        group_name: `SEO Auto ${data.project_id} ${new Date().toISOString().slice(0,10)}`
      })
    });
    const json = await resp.json();
    results.push({ batch: i + 1, count: names.length, status: json.result || json.status || 'sent', errors: json.errors || null });
  } catch(e) {
    results.push({ batch: i + 1, count: names.length, status: 'error', error: e.message });
  }
}

const successBatches = results.filter(r => r.status !== 'error').length;
const totalAdded = results.filter(r => r.status !== 'error').reduce((s, r) => s + r.count, 0);

return [{ json: {
  ...data,
  add_results: results,
  added_count: totalAdded,
  success_batches: successBatches,
  total_batches: results.length
}}];

