const data = $input.first().json;
const validate = $('Validate Input + Auth').first().json;

// ── Реальные ML-фичи из данных кластеров ──
const keywords = data.all_keywords || [];
const avgVolume = keywords.length > 0 
  ? keywords.reduce((s, k) => s + (k.search_volume || 0), 0) / keywords.length 
  : 0;

const commercialRatio = keywords.length > 0
  ? keywords.filter(k => k.intent === 'commercial' || k.page_type === 'commercial').length / keywords.length
  : 0;

const clusterNames = [...new Set(keywords.map(k => k.cluster_name).filter(Boolean))];

const mlPayload = {
  project_id: validate.project_id,
  keywords_count: keywords.length,
  new_keywords_count: data.keywords_new || 0,
  clusters_count: data.clusters_count || 0,
  avg_search_volume: Math.round(avgVolume),
  commercial_ratio: Math.round(commercialRatio * 100) / 100,
  unique_clusters: clusterNames.length,
  city: validate.city,
  has_rag_context: !!(data.rag_context && data.rag_context.length > 0),
  duplicate_ratio: data.keywords_total > 0 
    ? Math.round((data.duplicates_skipped / data.keywords_total) * 100) / 100 
    : 0
};

return [{ json: { ...data, ml_payload: mlPayload } }];

const features = $('Prepare ML Features (Real Data)').first().json;
let mlResult = {};
try { mlResult = $input.first().json; } catch(e) {}

return [{ json: {
  ...features,
  ml_aeo_score: mlResult.score ?? null,
  ml_aeo_label: mlResult.label ?? null,
  ml_confidence: mlResult.confidence ?? null,
  ml_model_version: mlResult.model_version ?? 'unknown',
  ml_is_rule_based: mlResult.is_rule_based ?? true
}}];

const validate = $('Validate Input + Auth').first().json;
const prep = $('Prepare Keywords + Dedup').first().json;
const ml = $('Merge ML Result').first().json;

let searchResult = {};
try { searchResult = $('Topvisor Enable Searchers').first().json; } catch(e) {}

// ── Гранулярный QC Score (7 критериев) ──
let qc = 0;
const qcDetails = {};

// 1. Ключи добавлены (0-25)
const addedRatio = prep.keywords_new > 0 ? (ml.added_count || 0) / prep.keywords_new : 0;
qcDetails.keywords_added = Math.round(addedRatio * 25);
qc += qcDetails.keywords_added;

// 2. Searchers включены (0-20)
const searchersOk = searchResult.result === 'success' || searchResult.status === 'success' || (Object.keys(searchResult).length > 0 && !searchResult.error);
qcDetails.searchers_enabled = searchersOk ? 20 : 0;
qc += qcDetails.searchers_enabled;

// 3. Дедупликация работает (0-15)
qcDetails.dedup_applied = prep.existing_in_topvisor > 0 ? 15 : (prep.keywords_new === prep.keywords_total ? 10 : 15);
qc += qcDetails.dedup_applied;

// 4. Кластеры покрыты (0-15)
const clusterCoverage = prep.clusters_count > 0 ? Math.min(1, prep.keywords_total / (prep.clusters_count * 3)) : 0;
qcDetails.cluster_coverage = Math.round(clusterCoverage * 15);
qc += qcDetails.cluster_coverage;

// 5. ML предсказание получено (0-10)
qcDetails.ml_prediction = ml.ml_aeo_score !== null ? 10 : 0;
qc += qcDetails.ml_prediction;

// 6. RAG контекст использован (0-10)
qcDetails.rag_context = prep.rag_context && prep.rag_context.length > 50 ? 10 : 0;
qc += qcDetails.rag_context;

// 7. Оба региона настроены (0-5)
qcDetails.regions_configured = (validate.yandex_region && validate.google_region) ? 5 : 0;
qc += qcDetails.regions_configured;

const response = {
  status: qc >= 60 ? 'success' : qc >= 30 ? 'partial' : 'failed',
  project_id: validate.project_id,
  topvisor_project_id: validate.topvisor_project_id,
  city: validate.city,
  keywords_total: prep.keywords_total,
  keywords_new_added: ml.added_count || 0,
  keywords_duplicates_skipped: prep.duplicates_skipped,
  clusters_count: prep.clusters_count,
  yandex_region: validate.yandex_region,
  google_region: validate.google_region,
  qc_score: qc,
  qc_max: 100,
  qc_details: qcDetails,
  ml: {
    aeo_score: ml.ml_aeo_score,
    aeo_label: ml.ml_aeo_label,
    confidence: ml.ml_confidence,
    model_version: ml.ml_model_version,
    is_rule_based: ml.ml_is_rule_based
  },
  searchers_result: searchResult.result || searchResult,
  version: 'v3.0',
  timestamp: new Date().toISOString(),
  started_at: validate.started_at,
  duration_ms: new Date() - new Date(validate.started_at)
};

return [{ json: response }];

